// Inline OCR: OpenAI Vision + update bandeja
const prep = $('Preparar Datos Ingesta').first().json;
const bandeja = $input.first().json; // from Crear Entrada Bandeja
const b64 = prep.base64;
const mime = prep.mime_type || 'image/jpeg';
const orgNombre = prep.org_nombre || '';
const SUPABASE_URL = prep.supabase_url;
const SUPABASE_KEY = prep.supabase_key;

let promptContext = '';
if (orgNombre) {
  promptContext = 'IMPORTANTE: La empresa que sube esta factura es "' + orgNombre + '". Esta empresa es el CLIENTE/RECEPTOR de la factura. El proveedor/emisor es la OTRA empresa que aparece en el documento. No confundas receptor con emisor.\n\n';
}

const prompt = promptContext + 'Extrae los datos de esta factura y devuelve SOLO un JSON valido (sin markdown, sin ```json, sin texto adicional) con esta estructura exacta:\n{\n  "prov": "nombre del proveedor o emisor de la factura (NO el receptor/cliente)",\n  "nif": "NIF o CIF del emisor/proveedor",\n  "direccion": "direccion fiscal del emisor/proveedor",\n  "cp": "codigo postal del emisor/proveedor",\n  "ciudad": "ciudad del emisor/proveedor",\n  "pais": "pais del emisor/proveedor (codigo ISO 2 letras, ej: ES)",\n  "telefono": "telefono del emisor/proveedor",\n  "email": "email del emisor/proveedor",\n  "num_factura": "numero de factura tal como aparece en el documento",\n  "fecha": "YYYY-MM-DD",\n  "vto": "YYYY-MM-DD o null si no hay fecha de vencimiento",\n  "base": 0.00,\n  "iva": 0.00,\n  "iva_pct": 21,\n  "irpf_pct": 0,\n  "descuento_pct": 0,\n  "total": 0.00,\n  "categoria": "una de: Suministros, Alquiler, Software, Material, Servicios, Personal, Seguros, Fiscal, Otros",\n  "conceptos": ["concepto1", "concepto2"],\n  "forma_pago": "Transferencia, Domiciliacion, Tarjeta, Efectivo, o como aparezca",\n  "iban": "numero IBAN si aparece en la factura",\n  "moneda": "codigo ISO moneda, ej: EUR, USD",\n  "confianza": 0.95\n}\nDevuelve solo los campos que encuentres en la factura. Omite los que no aparezcan. Si no puedes extraer un campo numerico, pon 0. Si no puedes extraer un campo de texto, omitelo.';

const content = [];
if (mime === 'application/pdf') {
  content.push({ type: 'file', file: { filename: prep.filename || 'factura.pdf', file_data: 'data:application/pdf;base64,' + b64 } });
} else {
  content.push({ type: 'image_url', image_url: { url: 'data:' + mime + ';base64,' + b64 } });
}
content.push({ type: 'text', text: prompt });

// Call OpenAI Vision
let datos;
try {
  const resp = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.openai.com/v1/chat/completions',
    headers: {
      'Authorization': 'Bearer [REDACTED-SECRET]',
      'Content-Type': 'application/json',
    },
    body: {
      model: 'gpt-4o-mini',
      max_tokens: 1024,
      messages: [{ role: 'user', content: content }]
    },
    json: true,
  });

  const text = resp.choices?.[0]?.message?.content || '{}';
  let clean = text.trim();
  if (clean.startsWith('```')) {
    clean = clean.replace(/^```[a-z]*\n?/, '').replace(/\n?```$/, '');
  }
  datos = JSON.parse(clean);
} catch(e) {
  datos = { prov: null, total: 0, categoria: 'Otros', confianza: 0 };
}

// Update bandeja_ingesta with OCR results
await this.helpers.httpRequest({
  method: 'PATCH',
  url: `${SUPABASE_URL}/rest/v1/bandeja_ingesta?id=eq.${bandeja.id}`,
  headers: {
    'apikey': SUPABASE_KEY,
    'Authorization': `Bearer ${SUPABASE_KEY}`,
    'Content-Type': 'application/json',
    'Prefer': 'return=representation',
  },
  body: {
    estado: 'listo',
    progreso: 100,
    datos_extraidos: datos,
    emisor: datos.prov || null,
  },
  json: true,
});

// Also update the factura record with extracted data
const factura_id = bandeja.factura_id;
if (factura_id && datos.num_factura) {
  const updateBody = {};
  if (datos.num_factura) updateBody.num = datos.num_factura;
  if (datos.fecha) updateBody.fecha = datos.fecha;
  if (datos.vto) updateBody.vto = datos.vto;
  if (datos.base) updateBody.base = datos.base;
  if (datos.iva_pct) updateBody.iva_pct = datos.iva_pct;
  if (datos.irpf_pct) updateBody.irpf_pct = datos.irpf_pct;
  if (datos.total) updateBody.total = datos.total;
  if (datos.categoria) updateBody.categoria = datos.categoria;
  if (datos.forma_pago) updateBody.forma_pago = datos.forma_pago;
  if (datos.moneda) updateBody.moneda = datos.moneda;

  if (Object.keys(updateBody).length > 0) {
    await this.helpers.httpRequest({
      method: 'PATCH',
      url: `${SUPABASE_URL}/rest/v1/facturas?id=eq.${factura_id}`,
      headers: {
        'apikey': SUPABASE_KEY,
        'Authorization': `Bearer ${SUPABASE_KEY}`,
        'Content-Type': 'application/json',
      },
      body: updateBody,
      json: true,
    });
  }
}

return [{ json: { success: true, bandeja_id: bandeja.id, datos_extraidos: datos } }];

