const result = await this.helpers.httpRequest({
  method: 'GET',
  url: `${SUPABASE_URL}/rest/v1/catalogo_servicios?org_id=eq.${orgId}&activo=eq.true&select=nombre,precio_orientativo,iva_pct,unidad`,
