const result = await this.helpers.httpRequest({
  method: 'GET',
  url: `${SUPABASE_URL}/rest/v1/clientes?org_id=eq.${orgId}&select=id,nombre,nif,email`,
  headers: {
    'apikey': SUPABASE_KEY,
    'Authorization': `Bearer ${SUPABASE_KEY}`
  },
  json: true
});

return JSON.stringify(result || []);

const raw = $json.output || $json.text || '';
let data;
try {
  const jsonMatch = raw.match(/\{[\s\S]*\}/);
  data = JSON.parse(jsonMatch ? jsonMatch[0] : raw);
} catch (e) {
  return [{ json: {
    error: true,
    message: 'El agente no devolvio un JSON valido. Intenta de nuevo con un audio mas claro.',
    raw_from: $('Preparar Input Agente').first().json.raw_from,
    phone_number_id: $('Preparar Input Agente').first().json.phone_number_id
  } }];
}

const lineas = (data.lineas || []).map(l => {
  const base = l.cantidad * l.precio_unitario;
  const descLinea = base * ((l.descuento_pct || 0) / 100);
  const baseNeta = base - descLinea;
  const iva = baseNeta * ((l.iva_pct || 21) / 100);
  return { ...l, base: baseNeta, iva };
});

const subtotal = lineas.reduce((s, l) => s + l.base, 0);
const descGlobalPct = data.descuento_global_pct || 0;
const descGlobal = subtotal * (descGlobalPct / 100);
const baseTotal = subtotal - descGlobal;
const ivaTotal = lineas.reduce((s, l) => s + l.iva, 0) * (1 - descGlobalPct / 100);
const total = baseTotal + ivaTotal;

const fmt = n => n.toFixed(2).replace('.', ',');

let resumen = `*${(data.tipo || 'factura').toUpperCase()}*\n`;
resumen += `Cliente: ${data.cliente?.nombre || 'Sin nombre'}\n\n`;
lineas.forEach(l => {
  resumen += `- ${l.cantidad}x ${l.descripcion}: ${fmt(l.precio_unitario)} EUR/u = ${fmt(l.cantidad * l.precio_unitario)} EUR`;
  if ((l.descuento_pct || 0) > 0) resumen += ` (-${l.descuento_pct}%)`;
  resumen += '\n';
});
resumen += '\n';
if (descGlobalPct > 0) resumen += `Dto global: ${descGlobalPct}%\n`;
resumen += `Base: ${fmt(baseTotal)} EUR\n`;
resumen += `IVA: ${fmt(ivaTotal)} EUR\n`;
resumen += `*TOTAL: ${fmt(total)} EUR*`;

return [{ json: {
  error: false,
  data,
  resumen,
  totales: { base: baseTotal, iva: ivaTotal, total },
  raw_from: $('Preparar Input Agente').first().json.raw_from,
  phone_number_id: $('Preparar Input Agente').first().json.phone_number_id
}}];

